INSERT INTO `alarm_behavior_dict` VALUES ('FENCE_ENTRY','非法闯入','围栏告警','high','人员非法闯入电子围栏区域','location'),('FENCE_EXIT','非法越界','围栏告警','high','人员非法离开电子围栏区域','location'),('FIRE_AFTER_NO_CHECK','余火未处置','动火作业','high','动火结束后未彻底处置余火','video'),('FIRE_BAD_TOOL','动火工具损坏','动火作业','high','动火工具漏气/损坏/气瓶间距不足','video'),('FIRE_COMBUSTIBLE','可燃物未清理','动火作业','high','动火点周边可燃物未清理','video'),('FIRE_CROSS_WORK','交叉作业无防护','动火作业','high','交叉作业未采取防火措施','video'),('FIRE_NO_EXTINGUISHER','无消防器材','动火作业','high','动火现场未配备消防器材','video'),('FIRE_NO_GUARD','无动火监护人','动火作业','high','动火作业未安排专职监护人','video'),('FIRE_NO_SIGN','无警示标识','动火作业','medium','动火现场未设置警示标识','video'),('HEIGHT_BAD_BELT','使用三点式安全带','高处作业','medium','未按要求佩戴五点式安全带','video'),('HEIGHT_BAD_WEATHER','恶劣天气作业','高处作业','high','大风/暴雨天气下高处作业','video'),('HEIGHT_LADDER_ANGLE','梯子角度过大','高处作业','medium','梯子与地面夹角大于75°','video'),('HEIGHT_LADDER_DOUBLE','两人同梯作业','高处作业','high','两人同时在梯子上作业','video'),('HEIGHT_LADDER_NO_GUARD','梯子作业无专人监护','高处作业','medium','攀登作业无专人监护','video'),('HEIGHT_LADDER_UNSTABLE','梯子不稳固','高处作业','medium','梯子使用时不稳固','video'),('HEIGHT_NO_BELT','未系安全带','高处作业','high','高处作业人员未系安全带','video'),('HEIGHT_NO_HELMET','未戴安全帽','高处作业','high','高处作业人员未佩戴安全帽','video'),('HEIGHT_NO_SIGN','无警示标识','高处作业','low','现场无验收牌/警示标牌','video'),('HEIGHT_PHONE_PLAY','玩手机','高处作业','low','作业时玩手机','video'),('HEIGHT_PLATFORM_NO_RAIL','操作平台无防护栏杆','高处作业','high','操作平台未设置防护栏杆','video'),('HEIGHT_PLATFORM_NOT_FULL','脚手板未满铺','高处作业','medium','操作平台脚手板未满铺','video'),('HEIGHT_SMOKING','吸烟','高处作业','low','作业时吸烟','video'),('HEIGHT_THROW_OBJECTS','抛掷物料','高处作业','high','高处抛掷物料','video'),('LIFT_BAD_SLING','吊索具缺陷','吊装作业','high','吊索具存在断丝/磨损/裂纹','video'),('LIFT_IN_RADIUS','无关人员进入回转半径','吊装作业','high','无关人员进入吊装回转半径','video'),('LIFT_NO_GUARD','无专职监护人','吊装作业','high','吊装作业未安排专职监护人','video'),('LIFT_NO_SIGN','无警示标识','吊装作业','medium','吊装现场未设置警示标识','video'),('LIFT_OUTRIGGER','支腿未完全伸出','吊装作业','high','吊车支腿未完全伸出或无垫板','video'),('LIFT_POST_NO_RECOVER','吊后未归位','吊装作业','low','吊装结束后吊索具未归位','video'),('LIFT_UNFIXED','被吊物未固定','吊装作业',