  `recording_path` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `recording_status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `recording_error` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `device_id` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `fence_id` int DEFAULT NULL,
  `project_id` int DEFAULT NULL COMMENT '所属项目',
  PRIMARY KEY (`id`),
  KEY `fence_id` (`fence_id`),
  KEY `project_id` (`project_id`),
  KEY `ix_alarm_records_device_id` (`device_id`),
  KEY `ix_alarm_records_id` (`id`),
  CONSTRAINT `alarm_records_ibfk_1` FOREIGN KEY (`fence_id`) REFERENCES `electronic_fences` (`id`),
  CONSTRAINT `alarm_records_ibfk_2` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3161 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
