--
-- Table structure for table `alarms`
--

DROP TABLE IF EXISTS `alarms`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `alarms` (
  `id` int NOT NULL AUTO_INCREMENT,
  `source_type` enum('video','fence') NOT NULL COMMENT 'video/fence',
  `behavior_code` varchar(50) NOT NULL COMMENT '行为代码（关联字典表）',
  `confidence` decimal(5,2) DEFAULT NULL COMMENT '置信度',
  `severity` enum('low','medium','high') NOT NULL COMMENT '实际等级（可能覆盖字典默认值）',
  `status` enum('pending','resolved','ignored') DEFAULT 'pending' COMMENT '处理状态',
  `trigger_device_id` int DEFAULT NULL,
  `trigger_device_name` varchar(100) DEFAULT NULL COMMENT '触发设备名称',
  `captured_person_name` varchar(50) DEFAULT NULL COMMENT '视频拍到的人员姓名',
  `captured_person_label` varchar(100) DEFAULT NULL COMMENT 'AI识别标签',
  `snapshot_url` varchar(500) DEFAULT NULL COMMENT '告警截图',
  `video_clip_url` varchar(500) DEFAULT NULL COMMENT '告警视频片段',
  `fence_id` int DEFAULT NULL,
  `fence_code` varchar(50) DEFAULT NULL COMMENT '围栏编号',
  `fence_name` varchar(100) DEFAULT NULL,
  `behavior` enum('entry','exit') DEFAULT NULL,
  `bound_device_id` int DEFAULT NULL COMMENT '绑定的定位设备ID',
  `bound_person_name` varchar(50) DEFAULT NULL,
  `bound_person_phone` varchar(20) DEFAULT NULL,
  `lat` decimal(10,6) DEFAULT NULL,
  `lng` decimal(10,6) DEFAULT NULL,
  `location_desc` varchar(255) DEFAULT NULL,
  `project_id` int NOT NULL,
  `branch_id` int NOT NULL,
  `alarm_time` datetime NOT NULL,
  `resolved_by` varchar(50) DEFAULT NULL,
  `resolved_at` datetime DEFAULT NULL,
  `resolution_remark` text,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `resolved_by_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '处理人工号',
  PRIMARY KEY (`id`),
  KEY `idx_behavior_code` (`behavior_code`),
  KEY `idx_severity` (`severity`),
  KEY `idx_status` (`status`),
  KEY `idx_project` (`project_id`),
  KEY `idx_alarm_time` (`alarm_time`),
  KEY `fk_alarms_trigger_device` (`trigger_device_id`),
  KEY `fk_alarms_fence_code` (`fence_code`),
  KEY `fk_alarms_resolved_by` (`resolved_by_code`),
  CONSTRAINT `fk_alarm_behavior` FOREIGN KEY (`behavior_code`) REFERENCES `alarm_behavior_dict` (`code`) ON DELETE RESTRICT,
  CONSTRAINT `fk_alarms_fence_code` FOREIGN KEY (`fence_code`) REFERENCES `fences` (`fence_code`) ON DELETE SET NULL,
  CONSTRAINT `fk_alarms_resolved_by` FOREIGN KEY (`resolved_by_code`) REFERENCES `personnel` (`employee_code`) ON DELETE SET NULL,
  CONSTRAINT `fk_alarms_trigger_device` FOREIGN KEY (`trigger_device_id`) REFERENCES `devices` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='告警记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

