DROP TABLE IF EXISTS `attendance_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `attendance_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `personnel_id` int NOT NULL COMMENT '人员ID（关联personnel表）',
  `check_time` datetime NOT NULL COMMENT '打卡时间',
  `type` enum('in','out') COLLATE utf8mb4_general_ci NOT NULL COMMENT '类型：in进场/out离场',
  `source` enum('card','face','gps','manual') COLLATE utf8mb4_general_ci DEFAULT 'card' COMMENT '打卡方式',
  `remark` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `branch_id` int DEFAULT NULL COMMENT '分公司ID',
  `project_id` int DEFAULT NULL COMMENT '项目ID',
  PRIMARY KEY (`id`),
  KEY `idx_personnel_time` (`personnel_id`,`check_time`),
  KEY `idx_date` (`check_time`),
  KEY `idx_type` (`type`),
  CONSTRAINT `fk_attendance_personnel` FOREIGN KEY (`personnel_id`) REFERENCES `personnel` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7675 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='考勤记录表';
