CREATE TABLE `electronic_fences` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '围栏名字',
  `project_region_id` int DEFAULT NULL COMMENT '所属项目区域ID',
