  `is_active` int DEFAULT NULL COMMENT '是否启用 1-启用 0-禁用',
  PRIMARY KEY (`id`),
  KEY `project_region_id` (`project_region_id`),
  KEY `ix_electronic_fences_id` (`id`),
  KEY `ix_electronic_fences_name` (`name`),
  CONSTRAINT `electronic_fences_ibfk_1` FOREIGN KEY (`project_region_id`) REFERENCES `project_regions` (`id`)
