  `branch_id` int NOT NULL COMMENT '所属分公司ID',
  `project_id` int NOT NULL COMMENT '所属项目ID',
  `name` varchar(100) NOT NULL COMMENT '围栏名称',
  `type` enum('circle','polygon') NOT NULL COMMENT '圆形/多边形',
