  `status` enum('active','scheduled','expired','disabled') NOT NULL DEFAULT 'scheduled' COMMENT '生效中/预约中/已过期/已禁用',
  `bound_device_ids` json DEFAULT NULL COMMENT '绑定的定位设备ID列表',
  `description` text COMMENT '描述',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_fence_code` (`fence_code`),
  KEY `idx_branch_project` (`branch_id`,`project_id`),
  KEY `idx_status` (`status`),
  KEY `idx_time_range` (`start_time`,`end_time`),
  KEY `project_id` (`project_id`),
  CONSTRAINT `fences_ibfk_1` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fences_ibfk_2` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='电子围栏表';
