DROP TABLE IF EXISTS `project_regions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `project_regions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '项目区域名字',
  `coordinates_json` text COLLATE utf8mb4_general_ci COMMENT '多边形顶点坐标JSON',
  `remark` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '区域备注',
  `project_id` int DEFAULT NULL COMMENT '所属项目ID',
  PRIMARY KEY (`id`),
  KEY `project_id` (`project_id`),
  KEY `ix_project_regions_id` (`id`),
  KEY `ix_project_regions_name` (`name`),
  CONSTRAINT `project_regions_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
