--
-- Table structure for table `projects`
--

DROP TABLE IF EXISTS `projects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `projects` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '项目ID',
  `branch_id` int NOT NULL COMMENT '所属分公司ID',
  `name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '项目名称',
  `code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '项目编号',
  `location` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '项目位置',
  `longitude` decimal(10,6) DEFAULT NULL COMMENT '经度',
  `latitude` decimal(10,6) DEFAULT NULL COMMENT '纬度',
  `manager_code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '项目管理员工号（关联personnel.employee_code）',
  `manager_name` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '项目管理员姓名',
  `manager_phone` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '负责人电话',
  `status` enum('active','warning','completed','suspended') COLLATE utf8mb4_general_ci DEFAULT 'active' COMMENT '项目状态',
  `progress` int DEFAULT '0' COMMENT '完成进度(%)',
  `safety_days` int NOT NULL DEFAULT '0' COMMENT '安全生产天数',
  `start_date` date DEFAULT NULL COMMENT '开工日期',
  `expected_end_date` date DEFAULT NULL COMMENT '预计竣工日期',
  `actual_end_date` date DEFAULT NULL COMMENT '实际竣工日期',
  `device_count` int DEFAULT '0' COMMENT '设备总数',
  `user_count` int DEFAULT '0' COMMENT '人员总数',
  `fence_count` int DEFAULT '0' COMMENT '电子围栏数',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `duration_days` int DEFAULT NULL COMMENT '工期（天）',
  `area_boundary` json DEFAULT NULL COMMENT '项目区域边界点 [[lng,lat],...]',
  `zoom_level` int DEFAULT '16' COMMENT '地图缩放级别',
  `center` json DEFAULT NULL COMMENT '项目中心点 [lng, lat]',
  `description` text COLLATE utf8mb4_general_ci,
  `manager` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `remark` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_branch_id` (`branch_id`),
  KEY `idx_status` (`status`),
  KEY `idx_progress` (`progress`),
  KEY `fk_projects_manager_code` (`manager_code`),
  CONSTRAINT `fk_projects_manager_code` FOREIGN KEY (`manager_code`) REFERENCES `personnel` (`employee_code`) ON DELETE SET NULL,
  CONSTRAINT `projects_ibfk_1` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

