  `username` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '登录用户名',
  `password` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '登录密码',
  `stream_url` text COLLATE utf8mb4_general_ci COMMENT '原始流地址 (RTSP/HLS/FLV)',
  `rtsp_url` text COLLATE utf8mb4_general_ci COMMENT '摄像头RTSP地址',
  `latitude` float DEFAULT NULL COMMENT '纬度 (GCJ-02)',
  `longitude` float DEFAULT NULL COMMENT '经度 (GCJ-02)',
  `status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '设备状态: online, offline',
  `remark` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注信息',
  `is_active` int DEFAULT NULL COMMENT '是否启用 1-启用 0-禁用',
  `stream_protocol` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `platform_type` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `access_source` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `ptz_source` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `device_serial` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `channel_no` int DEFAULT NULL,
  `supports_ptz` int NOT NULL DEFAULT '1',
  `supports_preset` int NOT NULL DEFAULT '1',
  `supports_cruise` int NOT NULL DEFAULT '1',
  `supports_zoom` int NOT NULL DEFAULT '1',
  `supports_focus` int NOT NULL DEFAULT '0',
  `branch_id` int DEFAULT NULL,
  `project_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_video_devices_name` (`name`),
  KEY `ix_video_devices_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1409 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
